import React, { useEffect, useMemo, useState } from "react";
import "./PrayerTimes.css";

/**
 * FIXED TIMEZONE UTILITIES
 * We lock everything to Vietnam time (Asia/Ho_Chi_Minh).
 * No mixing with local browser timezone.
 */

const VIETNAM_TZ = "Asia/Ho_Chi_Minh";

function getNowInVietnam(): Date {
  return new Date(
    new Date().toLocaleString("en-US", { timeZone: VIETNAM_TZ })
  );
}

function getVietnamDateForTime(hhmm: string, base: Date): Date {
  const [h, m] = hhmm.split(":").map(Number);

  // YYYY-MM-DD in Vietnam timezone
  const dateStr = base.toLocaleDateString("en-CA", {
    timeZone: VIETNAM_TZ,
  });

  // Explicit GMT+7 offset to avoid browser reinterpretation
  return new Date(
    `${dateStr}T${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}:00+07:00`
  );
}

function formatCountdown(totalSeconds: number): string {
  const s = Math.max(0, totalSeconds);
  const hh = String(Math.floor(s / 3600)).padStart(2, "0");
  const mm = String(Math.floor((s % 3600) / 60)).padStart(2, "0");
  const ss = String(s % 60).padStart(2, "0");
  return `${hh}:${mm}:${ss}`;
}

interface SessionTime {
  key: string;
  name: string;
  vietnamese: string;
  time: string; // HH:mm (Vietnam local time)
}

/**
 * Fixed monastery schedule (local, human-defined)
 * NOT astronomical like Muslim prayer times.
 */
const DEFAULT_SCHEDULE: SessionTime[] = [
  { key: "morning", name: "Morning Chanting", vietnamese: "Tụng Kinh Sáng", time: "05:30" },
  { key: "noon", name: "Noon Prayer", vietnamese: "Cầu Nguyện Trưa", time: "12:00" },
  { key: "evening", name: "Evening Chanting", vietnamese: "Tụng Kinh Chiều", time: "18:00" },
  { key: "night", name: "Night Meditation", vietnamese: "Thiền Tối", time: "20:00" },
];

const PrayerTimes: React.FC = () => {
  const [now, setNow] = useState<Date>(getNowInVietnam());

  // Tick every second, always Vietnam time
  useEffect(() => {
    if (typeof window === "undefined") return;
    const timer = setInterval(() => {
      setNow(getNowInVietnam());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  // Sort schedule once
  const schedule = useMemo(() => {
    return [...DEFAULT_SCHEDULE].sort((a, b) => {
      const [ah, am] = a.time.split(":").map(Number);
      const [bh, bm] = b.time.split(":").map(Number);
      return ah * 60 + am - (bh * 60 + bm);
    });
  }, []);

  const computed = useMemo(() => {
    if (!schedule.length) return null;

    let next = schedule[0];
    let target = getVietnamDateForTime(next.time, now);

    // Find next session today
    for (const s of schedule) {
      const t = getVietnamDateForTime(s.time, now);
      if (t.getTime() > now.getTime()) {
        next = s;
        target = t;
        break;
      }
    }

    // If all passed, roll to tomorrow first session
    if (target.getTime() <= now.getTime()) {
      const tomorrow = new Date(
        now.toLocaleString("en-US", { timeZone: VIETNAM_TZ })
      );
      tomorrow.setDate(tomorrow.getDate() + 1);

      next = schedule[0];
      target = getVietnamDateForTime(next.time, tomorrow);
    }

    const secondsLeft = Math.floor(
      (target.getTime() - now.getTime()) / 1000
    );

    return {
      nextSession: next,
      countdown: formatCountdown(secondsLeft),
    };
  }, [now, schedule]);

  if (!computed) return null;

  return (
    <div className="prayer-times-bar">
      <div className="prayer-info">
        <span className="prayer-label">Tiếp theo:</span>
        <span className="prayer-name">{computed.nextSession.vietnamese}</span>
        <span className="prayer-time">{computed.nextSession.time}</span>
        <span className="prayer-countdown">
          ({computed.countdown})
        </span>
      </div>
    </div>
  );
};

export default PrayerTimes;
