// Programs.tsx
import React from 'react';
import './programs.css';
import { useCMS } from '../../contexts/CMSContext';

interface ProgramsProps {
  programs?: any[]; // Keep for backward compatibility if needed
}

const Programs: React.FC<ProgramsProps> = ({ programs: propsPrograms }) => {
  const { cmsData } = useCMS();
  const { programsContent } = cmsData.pages.home;

  // Define the structure of a program item based on its usage
  type ProgramItem = {
    id: string;
    title: string;
    description?: string;
    links: { label: string; href: string }[];
    lectures: {
      id: string;
      title: string;
      subtitle: string;
      instructor?: string;
      image?: string;
      link?: string;
    }[];
    imageUrl: string;
  };

  // Use CMS data with safety checks
  const programData: ProgramItem[] = propsPrograms || (programsContent && programsContent.items) || [];

  if (!programData || programData.length === 0) return null;


  return (
    <section className="programs-section">
      <div className="programs-container">
        {programData.map((program: ProgramItem, index: number) => (
          <div
            key={program.id}
            className={`program-block ${index % 2 === 1 ? 'reverse' : ''}`}
          >
            {/* Image Area */}
            <div className="program-image">
              <img
                src={program.imageUrl}
                alt={program.title}
                className="program-image-content"
                onError={(e) => {
                  // Fallback if image fails to load
                  const target = e.target as HTMLImageElement;
                  target.style.display = 'none';
                  target.parentElement!.innerHTML = `
                    <div class="image-placeholder">
                      <div class="placeholder-content">
                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
                          <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5" strokeLinecap="round" strokeLinejoin="round"/>
                          <path d="M12 22V12" strokeLinecap="round" strokeLinejoin="round"/>
                        </svg>
                        <span>${program.title}</span>
                      </div>
                    </div>
                  `;
                }}
              />
            </div>

            {/* Content Area */}
            <div className="program-content">
              <div className="program-header">
                <h2 className="program-title">{program.title}</h2>
              </div>

              {/* Program Links */}
              <div className="program-links">
                <ul className="links-list">
                  {program.links.map((link, linkIndex) => (
                    <li key={linkIndex} className="link-item">
                      <a href={link.href || '#'} className="program-link">
                        {link.label}
                      </a>
                    </li>
                  ))}
                </ul>
              </div>

              {/* New Lectures Section - Horizontal Layout */}
              <div className="lectures-section">
                <h3 className="lectures-heading">Bài giảng mới</h3>
                <div className="lectures-grid">
                  {program.lectures.map((lecture) => (
                    <a
                      key={lecture.id}
                      href={lecture.link || '#'}
                      className="lecture-card"
                    >
                      <div className="lecture-thumbnail">
                        {lecture.image ? (
                          <img
                            src={lecture.image}
                            alt={lecture.title}
                            className="lecture-thumb-img"
                          />
                        ) : (
                          <div className="lecture-thumb-placeholder">
                            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
                              <rect x="3" y="3" width="18" height="18" rx="1" ry="1"></rect>
                              <circle cx="8.5" cy="8.5" r="1.5"></circle>
                              <polyline points="21 15 16 10 5 21"></polyline>
                            </svg>
                          </div>
                        )}
                      </div>
                      <div className="lecture-card-content">
                        <h4 className="lecture-title">{lecture.title}</h4>
                        <p className="lecture-subtitle">{lecture.subtitle}</p>
                        {lecture.instructor && (
                          <span className="lecture-instructor">{lecture.instructor}</span>
                        )}
                      </div>
                    </a>
                  ))}
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Programs;