// Updated Announcements.tsx component with proper class names
import React from 'react';
import './new.css';
import { useCMS } from '../../contexts/CMSContext';

interface AnnouncementsProps {
  featuredOnly?: boolean;
}

const Announcements: React.FC<AnnouncementsProps> = ({ featuredOnly = false }) => {
  const { cmsData } = useCMS();
  const { newsContent } = cmsData.pages.home;

  const announcements = newsContent.items;
  const featuredAnnouncement = announcements.find(item => item.isFeatured) || announcements[0];
  const regularAnnouncements = announcements.filter(item => !item.isFeatured).slice(0, 3);

  if (!announcements || announcements.length === 0) return null;

  return (
    <section className="announcements-section">
      <div className="announcements-container">
        {/* Two-column layout */}
        <div className="announcements-grid">
          {/* Left column - Featured announcement */}
          <div className="announcements-featured">
            <div className="featured-image">
              {featuredAnnouncement.image ? (
                <img src={featuredAnnouncement.image} alt={featuredAnnouncement.title} className="featured-img" />
              ) : (
                <div className="image-placeholder">
                  <div className="placeholder-content">
                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
                      <rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect>
                      <circle cx="8.5" cy="8.5" r="1.5"></circle>
                      <polyline points="21 15 16 10 5 21"></polyline>
                    </svg>
                    <span>Hình ảnh minh họa</span>
                  </div>
                </div>
              )}
            </div>

            <div className="featured-content">
              {featuredAnnouncement.category && (
                <div className="announcement-category">{featuredAnnouncement.category}</div>
              )}

              <h2 className="featured-title">{featuredAnnouncement.title}</h2>

              <p className="featured-subtitle">{featuredAnnouncement.subtitle}</p>

              {featuredAnnouncement.date && (
                <div className="announcement-date">{featuredAnnouncement.date}</div>
              )}
            </div>
          </div>

          {/* Right column - Announcements list */}
          <div className="announcements-list">
            <div className="list-header">
              <h2 className="section-title">{newsContent.sectionTitle}</h2>
              <div className="title-underline"></div>
            </div>

            <div className="announcements-items">
              {regularAnnouncements.map((item) => (
                <div className="announcement-item" key={item.id}>
                  <div className="announcement-thumb">
                    {item.image ? (
                      <img src={item.image} alt={item.title} className="thumb-img" />
                    ) : (
                      <div className="thumbnail-placeholder">
                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
                          <rect x="3" y="3" width="18" height="18" rx="1" ry="1"></rect>
                          <circle cx="8.5" cy="8.5" r="1.5"></circle>
                          <polyline points="21 15 16 10 5 21"></polyline>
                        </svg>
                      </div>
                    )}
                  </div>

                  <div className="announcement-text">
                    <h4>{item.title}</h4>
                    <p>{item.subtitle}</p>
                    {item.date && <span className="item-date">{item.date}</span>}
                  </div>
                </div>
              ))}
            </div>

            {/* Optional: View all link */}
          
          </div>
        </div>
      </div>
    </section>
  );
};

export default Announcements;